let age_median = 0
let fare_median = 0
let items = $input.all()
for (const e of items) {
  age_median += e.json.age
  fare_median += e.json.fare
}
return {
  items,
  age_median : parseInt(age_median/items.length),
  fare_median: fare_median/items.length
}

const toInt = (v) => (v !== null && v !== undefined && v !== "") ? parseInt(v) : 0;
const toFloat = (v) => (v !== null && v !== undefined && v !== "") ? parseFloat(v) : 0;
let age_group =
  $json.age < 12 ? 0 :
  $json.age < 18 ? 1 :
  $json.age < 40 ? 2 : 3;
return {
  survived: toInt($json.survived),
  pclass: toInt($json.pclass),
  sex: toInt($json.sex),
  age: toInt($json.age),
  age_group : age_group,
  fare: toFloat($json.fare)/100,

  family_size: toInt($json.family_size),
  is_alone: toInt($json.is_alone),
  embarked: toInt($json.embarked),
  title: toInt($json.title)
};

let rawname = $json.Name || "";

// Split safely
let [last_name, rest] = rawname.split(",").map(s => s?.trim());

// Split remaining parts
let parts = rest ? rest.split(/\s+/) : [];

// Extract title safely
let title = parts[0]?.replace(".", "") || null;

// Safe number parsing
const toInt = (val) => val ? parseInt(val) : null;
const toFloat = (val) => val ? parseFloat(val) : null;

// Build full name safely

return {
  survived: toInt($json.Survived),
  pclass: toInt($json.Pclass),

  title,

  sex: $json.Sex === "male" ? 1 : $json.Sex === "female" ? 0 : null,

  age: toInt($json.Age),
  sibSp: toInt($json.SibSp),
  parch: toInt($json.Parch),

  fare: toFloat($json.Fare),

  embarked: $json.Embarked || null
};

// Safe parsing helpers
const toInt = (v) => (v !== null && v !== undefined && v !== "") ? parseInt(v) : 0;
const toFloat = (v) => (v !== null && v !== undefined && v !== "") ? parseFloat(v) : 0;

// Calculate features
let sibSp = toInt($json.sibSp);
let parch = toInt($json.parch);

let family_size = sibSp + parch + 1;
let is_alone = family_size === 1 ? 1 : 0;

// Encode embarked
let embarked_code =
  $json.embarked === "S" ? 0 :
  $json.embarked === "C" ? 1 :
  $json.embarked === "Q" ? 2 : null;

// Optional: title encoding (VERY useful)
let title_map = {
  Mr: 0,
  Miss: 1,
  Mrs: 2,
  Master: 3
};

let title_code = title_map[$json.title] ?? 4; // others

return {
  survived: toInt($json.survived),
  pclass: toInt($json.pclass),
  sex: toInt($json.sex),
  age: toInt($json.age),
  fare: toFloat($json.fare),

  family_size,
  is_alone,
  embarked: embarked_code,
  title: title_code
};
